// Parse Atom feed, return latest 5 entries
const xml = $input.first().json.data || $input.first().json;
const text = typeof xml === 'string' ? xml : xml.toString();

const entries = [];
const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
let match;
while ((match = entryRegex.exec(text)) !== null) {
  const block = match[1];
  const get = (tag) => {
    const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`));
    return m ? m[1].trim() : null;
  };
  const getAttr = (tag, attr) => {
    const m = block.match(new RegExp(`<${tag}[^>]*${attr}="([^"]+)"`));
    return m ? m[1] : null;
  };
  entries.push({
    video_id: get('yt:videoId'),
    title: get('title'),
    published: get('published'),
    url: getAttr('link', 'href'),
    description: (block.match(/<media:description>([\s\S]*?)<\/media:description>/) || [])[1]?.trim() || ''
  });
}

return entries.slice(0, 5).map(e => ({ json: e }));

// Parse Claude output and bundle with transcript + metadata
const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let analysis;
try {
  analysis = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  return [];
}

const rss = $('Parse RSS').item.json;
const transcriptRaw = $('Fetch Transcript').item.json;
const transcript = transcriptRaw.content || transcriptRaw.text || transcriptRaw.transcript || '';

return [{
  json: {
    video_id: rss.video_id,
    video_url: rss.url,
    video_title: rss.title,
    transcript,
    ...analysis
  }
}];

