// Parse each channel's LLM output
function parseJSON(node) {
  const raw = node?.message?.content?.[0]?.text || node?.content || node?.text;
  try {
    return typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
  } catch (e) {
    return null;
  }
}

const ctx = $('Bundle Context').item.json;
const blog = parseJSON($('Claude: Blog Post').item.json);
const xThread = parseJSON($('Claude: X Thread').item.json);
const linkedin = parseJSON($('Claude: LinkedIn').item.json);

// Return 3 rows — one per channel
return [
  {
    json: {
      channel: 'blog',
      title: blog?.meta_title || ctx.video_title,
      meta_desc: blog?.meta_desc || '',
      body: blog?.body_markdown || '',
      source_ref: ctx.video_url,
      target_keyword: ctx.target_keyword,
      video_id: ctx.video_id,
    }
  },
  {
    json: {
      channel: 'x_thread',
      title: `[X thread] ${ctx.video_title}`,
      meta_desc: '',
      body: (xThread?.tweets || []).map((t, i) => `${i+1}/ ${t}`).join('\n\n'),
      source_ref: ctx.video_url,
      target_keyword: ctx.target_keyword,
      video_id: ctx.video_id,
    }
  },
  {
    json: {
      channel: 'linkedin',
      title: `[LinkedIn] ${ctx.video_title}`,
      meta_desc: '',
      body: linkedin?.post || '',
      source_ref: ctx.video_url,
      target_keyword: ctx.target_keyword,
      video_id: ctx.video_id,
    }
  }
];

const rows = $input.all().map(i => i.json);
const videoTitle = $('Bundle Context').first().json.video_title;
const videoUrl = $('Bundle Context').first().json.video_url;

const text = `🎬 *신규 영상 파생 콘텐츠 ${rows.length}종 준비*\n\n` +
  `*${videoTitle}*\n<${videoUrl}|YouTube에서 보기>\n\n` +
  rows.map(r => `• ${r.channel}: "${r.title}"`).join('\n') +
  `\n\n검토: Notion ContentDrafts (status=review 필터)`;

return [{ json: { text } }];
